// src/cli/utils/bun.ts
import { execSync } from "node:child_process";
import { existsSync } from "node:fs";
import { join } from "node:path";
function resolveBunPath() {
  const isWin = process.platform === "win32";
  const candidates = [];
  if (!isWin) {
    const home = process.env.HOME;
    if (home) {
      candidates.push(join(home, ".bun", "bin", "bun"));
    }
  }
  if (isWin) {
    if (process.env.USERPROFILE) {
      candidates.push(join(process.env.USERPROFILE, ".bun", "bin", "bun.exe"));
    }
    try {
      const discovered = execSync("where bun", {
        encoding: "utf-8",
        timeout: 3000,
        stdio: ["ignore", "pipe", "ignore"],
        windowsHide: true
      }).trim().split(/\r?\n/).map((entry) => entry.trim()).filter(Boolean).filter((entry) => !/chocolatey/i.test(entry));
      candidates.push(...discovered);
    } catch {}
  }
  const preferred = candidates.find((candidate) => existsSync(candidate));
  if (preferred) {
    return preferred;
  }
  try {
    let bunPath = execSync("which bun", {
      encoding: "utf-8",
      timeout: 3000,
      stdio: ["ignore", "pipe", "ignore"],
      windowsHide: true
    }).trim();
    if (bunPath) {
      if (isWin && /chocolatey/i.test(bunPath)) {
        bunPath = "";
      }
      if (isWin && /^\/[a-zA-Z]\//.test(bunPath)) {
        bunPath = bunPath[1].toUpperCase() + ":" + bunPath.slice(2);
      }
      return bunPath;
    }
  } catch {}
  throw new Error(`Bun runtime not found. The oh-my-claude proxy requires Bun.
` + `Install Bun: curl -fsSL https://bun.sh/install | bash
` + "Then restart your terminal and try again.");
}
var init_bun = () => {};

