// src/cli/utils/health.ts
import http from "node:http";
function checkHealth(controlPort) {
  return new Promise((resolve, reject) => {
    const req = http.get(`http://localhost:${controlPort}/health`, { timeout: 2000 }, (res) => {
      let data = "";
      res.on("data", (chunk) => {
        data += chunk;
      });
      res.on("end", () => {
        try {
          resolve(JSON.parse(data));
        } catch {
          reject(new Error("Invalid JSON"));
        }
      });
    });
    req.on("error", reject);
    req.on("timeout", () => {
      req.destroy();
      reject(new Error("Timeout"));
    });
  });
}

