// src/cli/commands/manage/config.ts
import { existsSync as existsSync42, readFileSync as readFileSync31, writeFileSync as writeFileSync24, mkdirSync as mkdirSync23 } from "node:fs";
import { join as join44, dirname as dirname10 } from "node:path";
import { homedir as homedir32 } from "node:os";
function registerConfigCommand(program2) {
  program2.command("config").description("Manage oh-my-claude omc configuration").option("--get <key>", "Get a config value").option("--set <key>=<value>", "Set a config value").option("--unset <key>", "Remove a config value").option("--list", "List all config values").action((options) => {
    const { c, ok } = createFormatters();
    const configPath = join44(homedir32(), ".claude", "oh-my-claude.json");
    const info = (text) => `${c.cyan}${text}${c.reset}`;
    let config = {};
    if (existsSync42(configPath)) {
      try {
        config = JSON.parse(readFileSync31(configPath, "utf-8"));
      } catch (error) {
        console.log(`Config file exists but is invalid. Starting with empty config.`);
      }
    }
    if (options.list) {
      console.log(`${c.bold}Current configuration:${c.reset}
`);
      if (Object.keys(config).length === 0) {
        console.log("  (no custom config set)");
      } else {
        for (const [key, value] of Object.entries(config)) {
          const formatted = JSON.stringify(value, null, 2);
          if (formatted.includes(`
`)) {
            const indented = formatted.replace(/\n/g, `
    `);
            console.log(`  ${key}: ${indented}`);
          } else {
            console.log(`  ${key}: ${formatted}`);
          }
        }
      }
      console.log(`
${info("Available keys:")}`);
      console.log("  debugTaskTracker - Enable debug logging for task-tracker hook");
      console.log("  debugHooks - Enable debug logging for all hooks");
      return;
    }
    if (options.get) {
      const key = options.get;
      if (key in config) {
        console.log(JSON.stringify(config[key], null, 2));
      } else {
        console.log(`Key '${key}' not found in config.`);
        console.log(`Run 'oh-my-claude omc config --list' to see all keys.`);
        process.exit(1);
      }
      return;
    }
    if (options.set) {
      const [key, ...valueParts] = options.set.split("=");
      const valueStr = valueParts.join("=");
      let value = valueStr;
      if (valueStr === "true")
        value = true;
      else if (valueStr === "false")
        value = false;
      else if (!isNaN(Number(valueStr)))
        value = Number(valueStr);
      config[key] = value;
      const configDir = dirname10(configPath);
      if (!existsSync42(configDir)) {
        mkdirSync23(configDir, { recursive: true });
      }
      writeFileSync24(configPath, JSON.stringify(config, null, 2));
      console.log(ok(`Set ${key} = ${JSON.stringify(value)}`));
      console.log(`
${info("Restart Claude Code for changes to take effect.")}`);
      return;
    }
    if (options.unset) {
      const key = options.unset;
      if (!(key in config)) {
        console.log(`Key '${key}' not found in config.`);
        process.exit(1);
      }
      delete config[key];
      writeFileSync24(configPath, JSON.stringify(config, null, 2));
      console.log(ok(`Unset ${key}`));
      return;
    }
    console.log(`${c.bold}Manage oh-my-claude omc configuration${c.reset}
`);
    console.log("Usage:");
    console.log("  oh-my-claude omc config --list");
    console.log("  oh-my-claude omc config --get <key>");
    console.log("  oh-my-claude omc config --set <key>=<value>");
    console.log("  oh-my-claude omc config --unset <key>");
    console.log(`
Run 'oh-my-claude omc config --list' to see available keys.`);
  });
}

