async function ollamaRootAction() {
  const { c, ok, fail, warn, dimText } = createFormatters();
  console.log(`${c.bold}Ollama Embedding Setup${c.reset}  ${c.dim}(for oh-my-claude memory)${c.reset}
`);
  if (!isOllamaInstalled()) {
    console.log(warn("Ollama is not installed."));
    console.log(`  Install it first: ${c.cyan}omc tools install ollama${c.reset}`);
    console.log(`  Or visit: ${dimText("https://ollama.com")}`);
    process.exit(1);
  }
  const running = isOllamaRunning();
  if (!running) {
    console.log(warn("Ollama is installed but not running."));
    console.log(`  Start it with: ${c.cyan}ollama serve${c.reset}`);
    console.log(`  ${dimText("Tip: set up ollama as a background service so it starts automatically.")}
`);
  } else {
    console.log(ok(`Ollama is running (http://localhost:11434)
`));
  }
  const pulled = getPulledModels();
  const embeddingPulled = pulled.filter(isEmbeddingModel);
  if (embeddingPulled.length > 0) {
    console.log(`${c.bold}Pulled embedding models:${c.reset}`);
    for (const m of embeddingPulled) {
      const meta = POPULAR_EMBEDDING_MODELS.find((e) => m.startsWith(e.name));
      console.log(`  ${c.green}вЬУ${c.reset} ${m}${meta ? `  ${c.dim}${meta.dimensions}d${c.reset}` : ""}`);
    }
    console.log();
  }
  const { select } = await Promise.resolve().then(() => (init_esm15(), exports_esm));
  const action = await select({
    message: "What would you like to do?",
    choices: [
      { name: "Pull a popular embedding model", value: "pull" },
      { name: "Configure memory to use a pulled model", value: "use" },
      { name: "Show status only", value: "status" },
      { name: "Cancel", value: "cancel" }
    ]
  });
  if (action === "cancel") {
    console.log(dimText("Cancelled."));
    return;
  }
  if (action === "status") {
    await statusAction();
    return;
  }
  if (action === "pull") {
    await pullAction(undefined);
    return;
  }
  if (action === "use") {
    await useAction(undefined);
    return;
  }
}
async function statusAction() {
  const { c, ok, fail, warn, dimText } = createFormatters();
  console.log(`${c.bold}Ollama Status${c.reset}
`);
  const installed = isOllamaInstalled();
  console.log(installed ? ok("Ollama installed") : fail("Ollama not installed"));
  if (!installed) {
    console.log(`  ${dimText("Install: omc tools install ollama")}`);
    return;
  }
  const running = isOllamaRunning();
  console.log(running ? ok("Ollama running (http://localhost:11434)") : warn("Ollama not running  (start: ollama serve)"));
  const pulled = getPulledModels();
  if (pulled.length === 0) {
    console.log(`
${dimText("No models pulled yet. Run: omc m ollama pull")}`);
    return;
  }
  const embeddingModels = pulled.filter(isEmbeddingModel);
  const otherModels = pulled.filter((m) => !isEmbeddingModel(m));
  if (embeddingModels.length > 0) {
    console.log(`
${c.bold}Embedding models:${c.reset}`);
    for (const m of embeddingModels) {
      const meta = POPULAR_EMBEDDING_MODELS.find((e) => m.startsWith(e.name));
      console.log(`  ${c.green}вЬУ${c.reset} ${c.cyan}${m}${c.reset}  ${dimText(meta ? `${meta.dimensions}d вАФ ${meta.description.split(";")[0]}` : "embedding model")}`);
    }
  } else {
    console.log(`
${dimText("No embedding models pulled yet. Run: omc m ollama pull")}`);
  }
  if (otherModels.length > 0) {
    console.log(`
${c.bold}Other models (not for embeddings):${c.reset}`);
    for (const m of otherModels) {
      console.log(`  ${c.dim}вЧЛ${c.reset} ${dimText(m)}`);
    }
  }
  console.log(`
${dimText("Run 'omc m ollama use' to configure oh-my-claude memory.")}`);
}
async function pullAction(modelArg) {
  const { c, ok, fail, warn, dimText } = createFormatters();
  if (!isOllamaInstalled()) {
    console.log(fail("Ollama is not installed. Run: omc tools install ollama"));
    process.exit(1);
  }
  let modelName = modelArg;
  if (!modelName) {
    const pulled = getPulledModels();
    const { select } = await Promise.resolve().then(() => (init_esm15(), exports_esm));
    const choices = POPULAR_EMBEDDING_MODELS.map((m) => {
      const alreadyPulled = pulled.some((p) => p.startsWith(m.name));
      const label = alreadyPulled ? `${m.display}  ${c.green}(pulled)${c.reset}  ${m.dimensions}d  ${m.size}  вАФ ${m.description}` : `${m.display}  ${m.dimensions}d  ${m.size}  вАФ ${m.description}`;
      return { name: label, value: m.name };
    });
    choices.push({ name: dimText("Cancel"), value: "__cancel__" });
    modelName = await select({
      message: "Select an embedding model to pull:",
      choices
    });
    if (modelName === "__cancel__") {
      console.log(dimText("Cancelled."));
      return;
    }
  }
  console.log(`
Pulling ${c.cyan}${modelName}${c.reset} from Ollama registry...
`);
  const result = spawnSync11("ollama", ["pull", modelName], { stdio: "inherit" });
  if (result.status !== 0) {
    console.log(`
${fail(`Failed to pull ${modelName}`)}`);
    process.exit(1);
  }
  console.log(`
${ok(`${modelName} pulled successfully`)}`);
  const { confirm } = await Promise.resolve().then(() => (init_esm15(), exports_esm));
  const meta = POPULAR_EMBEDDING_MODELS.find((m) => modelName.startsWith(m.name));
  const shouldConfigure = await confirm({
    message: `Configure oh-my-claude memory to use ${modelName} for embeddings?`,
    default: true
  });
  if (shouldConfigure) {
    await applyEmbeddingConfig(modelName, meta?.dimensions);
  } else {
    console.log(`
${dimText(`Run 'omc m ollama use ${modelName}' later to configure.`)}`);
  }
}
async function useAction(modelArg) {
  const { c, ok, fail, warn, dimText } = createFormatters();
  if (!isOllamaInstalled()) {
    console.log(fail("Ollama is not installed. Run: omc tools install ollama"));
    process.exit(1);
  }
  const pulled = getPulledModels();
  const embeddingPulled = pulled.filter(isEmbeddingModel);
  if (embeddingPulled.length === 0) {
    console.log(warn("No embedding models pulled yet."));
    console.log(`  Pull one first: ${c.cyan}omc m ollama pull${c.reset}`);
    if (pulled.length > 0) {
      console.log(`  ${dimText(`(${pulled.length} non-embedding model(s) found вАФ not suitable for memory search)`)}`);
    }
    return;
  }
  let modelName = modelArg;
  if (!modelName) {
    const { select } = await Promise.resolve().then(() => (init_esm15(), exports_esm));
    const choices = [
      ...embeddingPulled.map((m) => {
        const meta2 = POPULAR_EMBEDDING_MODELS.find((e) => m.startsWith(e.name));
        return {
          name: meta2 ? `${m}  ${dimText(`${meta2.dimensions}d вАФ ${meta2.description.split(";")[0]}`)}` : `${m}  ${dimText("embedding model")}`,
          value: m
        };
      }),
      { name: dimText("Cancel"), value: "__cancel__" }
    ];
    modelName = await select({
      message: "Select embedding model to use for memory:",
      choices
    });
    if (modelName === "__cancel__") {
      console.log(dimText("Cancelled."));
      return;
    }
  } else {
    const isPulled = pulled.some((p) => p.startsWith(modelName));
    const isEmbed = isEmbeddingModel(modelName);
    const { confirm } = await Promise.resolve().then(() => (init_esm15(), exports_esm));
    if (!isPulled) {
      console.log(warn(`${modelName} does not appear to be pulled yet.`));
      const proceed = await confirm({ message: "Configure anyway?", default: false });
      if (!proceed)
        return;
    } else if (!isEmbed) {
      console.log(warn(`${modelName} does not appear to be an embedding model.`));
      console.log(dimText("  Non-embedding models cannot generate vector embeddings for memory search."));
      const proceed = await confirm({ message: "Configure anyway?", default: false });
      if (!proceed)
        return;
    }
  }
  const meta = POPULAR_EMBEDDING_MODELS.find((m) => modelName.startsWith(m.name));
  await applyEmbeddingConfig(modelName, meta?.dimensions);
}
async function applyEmbeddingConfig(modelName, dimensions) {
  const { c, ok, fail, dimText } = createFormatters();
  console.log(`
Configuring oh-my-claude memory to use ${c.cyan}${modelName}${c.reset}...
`);
  const steps = [
    ["memory.embedding.provider", "custom", "Set provider to custom (OpenAI-compatible)"],
    ["memory.embedding.model", modelName, `Set model to ${modelName}`]
  ];
  if (dimensions) {
    steps.push(["memory.embedding.dimensions", String(dimensions), `Set dimensions to ${dimensions}`]);
  }
  let allOk = true;
  for (const [key, value, desc] of steps) {
    const success = setConfig(key, value);
    console.log(success ? `  ${ok(desc)}` : `  ${fail(`Failed: ${key}`)}`);
    if (!success)
      allOk = false;
  }
  console.log(`
${c.bold}Required environment variable:${c.reset}`);
  console.log(`  ${c.cyan}export EMBEDDING_API_BASE=http://localhost:11434/v1${c.reset}`);
  console.log(`  ${dimText("Add this to your shell profile (~/.zshrc or ~/.bashrc)")}
`);
  if (allOk) {
    console.log(ok("Memory embedding configured for Ollama."));
    console.log(dimText("Start Ollama (`ollama serve`) before using semantic memory search."));
  } else {
    console.log(fail("Some config steps failed. Try: omc m config --set <key>=<value>"));
  }
}
function registerOllamaCommand(parent) {
  const ollamaCmd = parent.command("ollama").description("Manage Ollama embedding models for memory semantic search").action(ollamaRootAction);
  ollamaCmd.command("status").description("Check Ollama running state and pulled embedding models").action(statusAction);
  ollamaCmd.command("pull [model]").description("Pull a popular embedding model from Ollama registry").action(pullAction);
  ollamaCmd.command("use [model]").description("Configure oh-my-claude memory to use a pulled Ollama model").action(useAction);
}

// src/cli/commands/manage/cleanup.ts
import { existsSync as existsSync45, readdirSync as readdirSync10, statSync as statSync8, rmSync as rmSync3, readFileSync as readFileSync34 } from "node:fs";
import { join as join47 } from "node:path";
function registerCleanupCommand(program2) {
  program2.command("cleanup").description("Clean up stale session data and temporary files").option("--dry-run", "Show what would be cleaned without deleting").option("--force", "Clean all sessions (including recent ones)").action((options) => {
    const { c, ok, fail, warn, dimText } = createFormatters();
    const dryRun = options.dryRun;
    const force = options.force;
    console.log(`oh-my-claude Cleanup
`);
    if (dryRun) {
      console.log(warn(`Dry run mode - no files will be deleted
`));
    }
    if (force) {
      console.log(warn(`Force mode - all sessions will be cleaned
`));
    }
    const sessionsDir = join47(INSTALL_DIR, "sessions");
    function isProcessRunning2(pid) {
      try {
        process.kill(pid, 0);
        return true;
      } catch {
        return false;
      }
    }
    let totalCleaned = 0;
    if (existsSync45(sessionsDir)) {
      console.log("Session directories:");
      const entries = readdirSync10(sessionsDir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.isDirectory()) {
          const sessionDir = join47(sessionsDir, entry.name);
          const dirName = entry.name;
          let shouldClean = false;
          let reason = "";
          if (dirName.startsWith("pid-")) {
            const pidStr = dirName.substring(4);
            const pid = parseInt(pidStr, 10);
            if (!isNaN(pid) && pid > 0) {
              if (!isProcessRunning2(pid)) {
                shouldClean = true;
                reason = `PID ${pid} not running`;
              } else if (force) {
                shouldClean = true;
                reason = `forced (PID ${pid} running)`;
              } else {
                console.log(`  ${dimText(dirName)} - active (PID running)`);
              }
            } else {
              shouldClean = true;
              reason = "invalid PID format";
            }
          } else {
            const stat = statSync8(sessionDir);
            const ageMs = Date.now() - stat.mtimeMs;
            const ageHours = Math.floor(ageMs / (60 * 60 * 1000));
            if (force) {
              shouldClean = true;
              reason = `old format (${ageHours}h old)`;
            } else if (ageHours > 1) {
              shouldClean = true;
              reason = `stale (${ageHours}h old)`;
            } else {
              console.log(`  ${dimText(dirName)} - recent (<1h old)`);
            }
          }
          if (shouldClean) {
            if (dryRun) {
              console.log(`  ${warn(dirName)} - would delete (${reason})`);
              totalCleaned++;
            } else {
              try {
                rmSync3(sessionDir, { recursive: true, force: true });
                console.log(`  ${ok(dirName)} - deleted (${reason})`);
                totalCleaned++;
              } catch (error) {
                console.log(`  ${fail(dirName)} - failed to delete`);
              }
            }
          }
        }
      }
      if (entries.length === 0) {
        console.log("  (no sessions found)");
      }
    } else {
      console.log("Session directories: (none)");
    }
    const ppidFile = join47(INSTALL_DIR, "current-ppid.txt");
    if (existsSync45(ppidFile)) {
      console.log(`
PPID tracking file:`);
      try {
        const content = readFileSync34(ppidFile, "utf-8").trim();
        const parts = content.split(":");
        const pid = parseInt(parts[0] ?? "", 10);
        const timestamp = parseInt(parts[1] ?? "", 10);
        const ageMs = Date.now() - timestamp;
        const ageMinutes = Math.floor(ageMs / (60 * 1000));
        if (!isNaN(pid) && pid > 0 && isProcessRunning2(pid) && !force) {
          console.log(`  ${dimText("current-ppid.txt")} - active (PID ${pid} running)`);
        } else {
          if (dryRun) {
            console.log(`  ${warn("current-ppid.txt")} - would delete (PID ${pid} not running, ${ageMinutes}m old)`);
            totalCleaned++;
          } else {
            rmSync3(ppidFile, { force: true });
            console.log(`  ${ok("current-ppid.txt")} - deleted (PID ${pid} not running)`);
            totalCleaned++;
          }
        }
      } catch {
        if (dryRun) {
          console.log(`  ${warn("current-ppid.txt")} - would delete (unreadable)`);
          totalCleaned++;
        } else {
          rmSync3(ppidFile, { force: true });
          console.log(`  ${ok("current-ppid.txt")} - deleted (unreadable)`);
          totalCleaned++;
        }
      }
    }
    const debugLog = join47(INSTALL_DIR, "task-tracker-debug.log");
    if (existsSync45(debugLog)) {
      console.log(`
Debug logs:`);
      const stat = statSync8(debugLog);
      const sizeKb = Math.round(stat.size / 1024);
      if (dryRun) {
        console.log(`  ${warn("task-tracker-debug.log")} - would delete (${sizeKb}KB)`);
        totalCleaned++;
      } else {
        rmSync3(debugLog, { force: true });
        console.log(`  ${ok("task-tracker-debug.log")} - deleted (${sizeKb}KB)`);
        totalCleaned++;
      }
    }
    console.log();
    if (dryRun) {
      console.log(`Dry run complete. Would clean ${totalCleaned} item(s).`);
    } else {
      console.log(`Cleanup complete. Removed ${totalCleaned} item(s).`);
    }
  });
}

// src/cli/commands/manage/coworker-log.ts
import {
  existsSync as existsSync47,
  readFileSync as readFileSync36,
  unwatchFile,
  watchFile,
  writeFileSync as writeFileSync27
} from "node:fs";
init_observability();
var STALENESS_THRESHOLD_MS = 90000;
var IDLE_EXIT_THRESHOLD_MS = 25000;
var PRINT_LINES = 50;
var PRINT_TRUNCATE = 500;
var LIVE_FLUSH_MS = 450;
var ANSI = {
  reset: "\x1B[0m",
  dim: "\x1B[2m",
  cyan: "\x1B[36m",
  white: "\x1B[37m",
  green: "\x1B[32m",
  yellow: "\x1B[33m",
  red: "\x1B[31m",
  bold: "\x1B[1m",
  blue: "\x1B[34m"
};
function relativeTime(isoTs) {
  const diffMs = Date.now() - new Date(isoTs).getTime();
  const diffS = Math.floor(diffMs / 1000);
  if (diffS < 5)
    return "just now";
  if (diffS < 60)
    return `${diffS}s ago`;
  const diffM = Math.floor(diffS / 60);
  if (diffM < 60)
    return `${diffM}m ago`;
  const diffH = Math.floor(diffM / 60);
  if (diffH < 24)
    return `${diffH}h ago`;
  return new Date(isoTs).toLocaleDateString();
}
function truncate(text, maxLen) {
  if (text.length <= maxLen)
    return text;
  return text.slice(0, maxLen) + ANSI.dim + "вА¶" + ANSI.reset;
}
function parseEntries(raw) {
  return raw.split(`
`).filter((line) => line.trim()).map((line) => {
    try {
      return JSON.parse(line);
    } catch {
      return null;
    }
  }).filter((entry) => entry !== null);
}
function contentForMerge(type) {
  return type === "text_delta" || type === "plan_update";
}
function toolActivityPrefix(content) {
  const idx = content.indexOf(`
`);
  return idx >= 0 ? content.slice(0, idx) : content;
}
function canMerge(left, right) {
  if (left.type !== right.type)
    return false;
  if (left.sessionId !== right.sessionId || left.taskId !== right.taskId) {
    return false;
  }
  if (left.model !== right.model)
    return false;
  if (contentForMerge(left.type)) {
    return true;
  }
  if (left.type === "tool_activity") {
    return toolActivityPrefix(left.content) === toolActivityPrefix(right.content);
  }
  return false;
}
function mergeEntries(left, right) {
  if (contentForMerge(left.type)) {
    return {
      ...right,
      ts: right.ts,
      content: `${left.content}${right.content}`,
      meta: {
        ...left.meta ?? {},
        ...right.meta ?? {}
      }
    };
  }
  if (left.type === "tool_activity") {
    const count = Number(left.meta?.count ?? 1) + 1;
    const prefix = toolActivityPrefix(left.content);
    return {
      ...right,
      ts: right.ts,
      content: prefix,
      meta: {
        ...left.meta ?? {},
        ...right.meta ?? {},
        count
      }
    };
  }
  return right;
}
function aggregateEntries(entries) {
  const aggregated = [];
  for (const entry of entries) {
    const previous = aggregated.at(-1);
    if (previous && canMerge(previous, entry)) {
      aggregated[aggregated.length - 1] = mergeEntries(previous, entry);
      continue;
    }
    aggregated.push(entry);
  }
  return aggregated;
}
function formatEntry(target, entry, truncateContent = false) {
  const rel = relativeTime(entry.ts);
  const dim = `${ANSI.dim}[${rel}]${ANSI.reset}`;
  const content = truncateContent ? truncate(entry.content, PRINT_TRUNCATE) : entry.content;
  const label = target.toUpperCase();
  switch (entry.type) {
    case "session_started":
      return `
${ANSI.dim}${"вФА".repeat(40)}${ANSI.reset}
` + `${ANSI.bold}${ANSI.blue}вЧП New ${label} Session${ANSI.reset}` + (entry.model ? ` ${ANSI.dim}(${entry.model})${ANSI.reset}` : "") + `  ${ANSI.dim}${new Date(entry.ts).toLocaleString()}${ANSI.reset}
` + `${ANSI.dim}  ${content}${ANSI.reset}`;
    case "task_started":
      return `${dim} ${ANSI.cyan}${ANSI.bold}TASK:${ANSI.reset}  ${content}`;
    case "text_delta":
      return `${dim} ${ANSI.white}${label}:${ANSI.reset} ${content}`;
    case "plan_update":
      return `${dim} ${ANSI.blue}PLAN:${ANSI.reset}  ${content}`;
    case "tool_activity": {
      const count = Number(entry.meta?.count ?? 1);
      const suffix = count > 1 ? ` ${ANSI.dim}√Ч${count}${ANSI.reset}` : "";
      const display = toolActivityPrefix(content);
      return `${dim} ${ANSI.yellow}TOOL:${ANSI.reset}  ${display}${suffix}`;
    }
    case "task_completed":
      return `${dim} ${ANSI.green}вЬУ DONE:${ANSI.reset} ${content}`;
    case "task_failed":
      return `${dim} ${ANSI.red}вЬЧ ERROR:${ANSI.reset} ${content}`;
    case "provider_event":
      return `${dim} ${ANSI.dim}EVENT:${ANSI.reset} ${content}`;
    default:
      return `${dim} ${entry.type}: ${content}`;
  }
}
function renderEntries(target, entries, options) {
  const source = options.raw ? entries : aggregateEntries(entries);
  return source.map((entry) => formatEntry(target, entry, options.truncateContent ?? false));
}

class LiveRenderer {
  target;
  raw;
  pending = null;
  flushTimer = null;
  constructor(target, raw) {
    this.target = target;
    this.raw = raw;
  }
  push(entries) {
    const source = this.raw ? entries : aggregateEntries(entries);
    for (const entry of source) {
      if (this.raw) {
        console.log(formatEntry(this.target, entry, false));
        continue;
      }
      if (this.pending && canMerge(this.pending, entry)) {
        this.pending = mergeEntries(this.pending, entry);
        this.scheduleFlush();
        continue;
      }
      this.flush();
      this.pending = entry;
      this.scheduleFlush();
    }
  }
  flush() {
    if (!this.pending)
      return;
    console.log(formatEntry(this.target, this.pending, false));
    this.pending = null;
    if (this.flushTimer) {
      clearTimeout(this.flushTimer);
      this.flushTimer = null;
    }
  }
  stop() {
    this.flush();
    if (this.flushTimer) {
      clearTimeout(this.flushTimer);
      this.flushTimer = null;
    }
  }
  scheduleFlush() {
    if (this.flushTimer) {
      clearTimeout(this.flushTimer);
    }
    this.flushTimer = setTimeout(() => this.flush(), LIVE_FLUSH_MS);
  }
}
function registerCoworkerLogSubcommand(parent, target, label) {
  const logPath = getCoworkerLogPath(target);
  const statusPath = getCoworkerStatusPath(target);
  const sub = parent.command(target).description(`Manage ${label} coworker and view activity`);
  sub.command("log").description(`View ${label} coworker activity log`).option("--print", "print last 50 entries and exit").option("--clear", "truncate the log file").option("--raw", "show raw event stream without aggregation").action((opts) => {
    const { c } = createFormatters();
    if (opts.clear) {
      try {
        writeFileSync27(logPath, "", "utf-8");
        console.log(`${c.green}вЬУ${c.reset} ${label} activity log cleared.`);
      } catch (err) {
        console.error(`${c.red}вЬЧ${c.reset} Failed to clear log: ${err}`);
        process.exit(1);
      }
      return;
    }
    if (opts.print) {
      if (!existsSync47(logPath)) {
        console.log(`${c.dim}No ${label} activity log found.${c.reset}`);
        return;
      }
      const entries = parseEntries(readFileSync36(logPath, "utf-8")).slice(-PRINT_LINES);
      if (entries.length === 0) {
        console.log(`${c.dim}Activity log is empty.${c.reset}`);
        return;
      }
      console.log(`${ANSI.bold}${label} Coworker Log${ANSI.reset} ${ANSI.dim}(last ${entries.length} entries${opts.raw ? ", raw" : ", aggregated"})${ANSI.reset}`);
      for (const line of renderEntries(target, entries, {
        truncateContent: true,
        raw: opts.raw
      })) {
        console.log(line);
      }
      return;
    }
    if (!existsSync47(logPath)) {
      console.log(`${c.dim}Waiting for ${label} activity log to be created...${c.reset}`);
    } else {
      const entries = parseEntries(readFileSync36(logPath, "utf-8")).slice(-20);
      if (entries.length > 0) {
        console.log(`${ANSI.dim}вФАвФАвФА recent history (${opts.raw ? "raw" : "aggregated"}) вФАвФАвФА${ANSI.reset}`);
        for (const line of renderEntries(target, entries, {
          raw: opts.raw
        })) {
          console.log(line);
        }
      }
    }
    console.log(`
${ANSI.dim}вФАвФАвФА live (${opts.raw ? "raw" : "aggregated"}, Ctrl+C to stop) вФАвФАвФА${ANSI.reset}
`);
    const renderer = new LiveRenderer(target, opts.raw ?? false);
    let lastSize = existsSync47(logPath) ? readFileSync36(logPath, "utf-8").length : 0;
    const viewerStartedAt = Date.now();
    const VIEWER_GRACE_MS = 1e4;
    const shouldExitFromStatus = () => {
      if (Date.now() - viewerStartedAt < VIEWER_GRACE_MS) {
        return false;
      }
      if (!existsSync47(statusPath)) {
        return false;
      }
      try {
        const statusJson = JSON.parse(readFileSync36(statusPath, "utf-8"));
        if (!statusJson.updatedAt) {
          return false;
        }
        const ageMs = Date.now() - statusJson.updatedAt;
        if (ageMs > STALENESS_THRESHOLD_MS) {
          return true;
        }
        if (["idle", "complete", "error"].includes(statusJson.state ?? "") && ageMs > IDLE_EXIT_THRESHOLD_MS) {
          return true;
        }
      } catch {}
      return false;
    };
    let exiting = false;
    const cleanExit = (message) => {
      if (exiting)
        return;
      exiting = true;
      try {
        renderer.stop();
      } catch {}
      try {
        unwatchFile(logPath);
      } catch {}
      try {
        clearInterval(statusPoll);
      } catch {}
      process.removeAllListeners("SIGINT");
      console.log(message);
      process.exitCode = 0;
    };
    const maybeExit = () => {
      if (!shouldExitFromStatus()) {
        return;
      }
      cleanExit(`
${ANSI.dim}${label} coworker stopped. Exiting viewer.${ANSI.reset}`);
    };
    watchFile(logPath, { interval: 300 }, () => {
      maybeExit();
      try {
        const content = readFileSync36(logPath, "utf-8");
        if (content.length <= lastSize) {
          lastSize = content.length;
          return;
        }
        const newEntries = parseEntries(content.slice(lastSize));
        lastSize = content.length;
        renderer.push(newEntries);
      } catch {
        lastSize = 0;
      }
    });
    const statusPoll = setInterval(maybeExit, 1000);
    process.on("SIGINT", () => {
      cleanExit(`
${ANSI.dim}Stopped.${ANSI.reset}`);
    });
  });
  return sub;
}

