function registerOpenCodeLogCommand(parent) {
  const sub = registerCoworkerLogSubcommand(parent, "opencode", "OpenCode");
  const { c } = createFormatters();
  sub.command("viewer").description("Open or re-attach the OpenCode coworker viewer").action(async () => {
    try {
      const { getOpenCodeCoworker: getOpenCodeCoworker2 } = await Promise.resolve().then(() => (init_coworker(), exports_coworker));
      const runtime = getOpenCodeCoworker2(process.cwd());
      await runtime.startSession();
      const attached = runtime.ensureViewer();
      if (attached) {
        console.log(`${c.green}вЬУ${c.reset} OpenCode viewer attached.`);
        return;
      }
      console.log(`${c.yellow}!${c.reset} OpenCode viewer could not be opened. Status + log remain available.`);
    } catch (error) {
      console.log(`${c.red}вЬЧ${c.reset} Failed to open OpenCode viewer: ${error}`);
      process.exit(1);
    }
  });
}

